解法:
最短路径的一个变形，就坐标映射为点就可以
代码:

```#include<stdio.h>
#include<algorithm>
#include<cmath>
#include<queue>
#include<vector>
#include<map>
using namespace std;
struct Node
{
    int to;
    long long  len;
    bool  operator<(const Node &a) const
    {
        return len  > a.len;
    }
};
struct xy
{
    int x;
    int y;
    bool  operator<(const xy &a) const
    {
        if(x == a.x)
            return y < a.y;
        else
        {
            return x < a.x;
        }

    }
};
bool isUsed[510];
long long ans[510];
