        int len = unique(v, v + n) - v;
       // printf("%d\n", len);
        for(int i = 0; i < n; i++)
            a[i] = lower_bound(v, v + len,a[i]) - v + 1;
        //for(int i = 0; i < n; i++)
        //    printf("%d ", a[i]);
      //  printf("\n");
        for(int i = 0; i <= n; i++){
            MAX[i] = -inf;MIN[i] = inf;
