            MAX[a[i]] = max(MAX[a[i]],i + 1);
            MIN[a[i]] = min(MIN[a[i]],i + 1);
           // printf("%d %d %d\n", i,MAX[i],MIN[i]);
        }
        int ans = 0;
        for(int i = 1; i <= len; i++)
        {
           // printf("%d %d %d\n", i,MAX[i],MIN[i]);
            if(MIN[i] > MAX[i - 1])
                dp[i] = dp[i - 1] + 1;
