{
    int t;
    scanf("%d", &t);
    while(t--){
        int a,b,c;
        scanf("%d%d%d", &a, &b, &c);
        int ans = 0;
        if(b < c/2){
            ans = b * 3;
        }
        else{
            ans += c/2 * 3;
            b -= c/2;
            if(a < b/2)
                ans += a * 3;
            else
            {
                ans += b/2 *3;
            }

        }
        printf("%d\n", ans);
    }
    return 0;
}
