## 题解：
转换为三进制，找到第一个为2的位置，然后在2之前找到第一个为0的位置，然后置为1，后面的全部置为0
## 代码：
```
#include<stdio.h>
#include<algorithm>
#include<string>
#include<string.h>
#include<stack>
#include<queue>
#include<set>
#include<map>
using namespace std;
int a[100];
long long POW(long long x, long long z)
{
    long long ans = 1;
    long long now = x;
    while(z){
        if(z&1)
            ans *= now;
        now = now * now;
        z >>= 1;
    }
    return ans;
}
int main()
{
    int t;
    scanf("%d", &t);
    while(t--){
        long long  n;
        scanf("%lld", &n);
        long long p = n;
        int len = 0;
        while(n){
            a[len] =  n %3;
            n /= 3;
            len++;
        }
        int sta = -1;
        for(int i = 0; i < len; i++)
        {
            if(a[i] == 2)
                sta = i;
        }
        if(sta == -1){
            printf("%lld\n",p);
        }
        else{
            int t = 0,i;
            for(i = sta + 1; i < len; i++){
                if(a[i] == 0){
                    t = i;
                    a[i] = 1;
                    break;
                }
            }
            if(i == len)
            {
                printf("%lld\n", POW(3,i));
            }
            else{
                long long ans = 0;
                for(int j = t; j < len; j++){
                    if(a[j] == 1)
                    {
                        ans += POW(3,j);
                    }
                }
                printf("%lld\n", ans);
            }
        }
    }
    return 0;
}
```
