# [164. 最大间距](https://leetcode-cn.com/problems/maximum-gap/)
1. 暴力排序，然后遍历(nlogn)
2. 将数组划分为不同的区间，每块区间的长度为（MAX - MIN)/(n - 1）,然后遍历相邻的区间，用后面区间的最小值 - 前面区间的最大值，最终ans为所有差中的最大值

    ```
    class Solution {
public:
    int maximumGap(vector<int>& nums) {
      int len = nums.size();
      if (len < 2)
        return 0;
      int Max = *max_element(nums.begin(), nums.end());
      int Min = *min_element(nums.begin(), nums.end());
      int d = max(1, (Max - Min) / (len - 1));
      int bucketSize = (Max - Min) / d + 1;
      vector<pair<long long, long long>> v(bucketSize, {999999999, -1});
      for (int i = 0; i < len; i++) {
        int index = (nums[i] - Min) / d;
        v[index].first = min(v[index].first, nums[i] * 1ll);
        v[index].second = max(v[index].second, nums[i] * 1ll);
      }
      long long ans = 0;
      int pre = -1;
      for (int i = 0; i < bucketSize; i++) {
        if (v[i].second == -1)
          continue;
        if (pre != -1 ) {
           ans = max(ans, v[i].first - v[pre].second);
        }
        pre = i;
      }
      return ans;
    }
};
```
# [454. 四数相加 II](https://leetcode-cn.com/problems/4sum-ii/)
1.将AB，CD分别处理成两个单独的vector，然后排序，转换为两数相加
```
class Solution {
public:
    int fourSumCount(vector<int>& A, vector<int>& B, vector<int>& C, vector<int>& D) {
      int len = A.size();
      vector<int> a;
      vector<int> b;
      for (int i = 0; i < len; i++) {
        for (int j = 0; j < len; j++) {
          a.push_back(A[i] + B[j]);
          b.push_back(C[i] + D[j]);
        }
      }
      sort(a.begin(), a.end());
      sort(b.begin(), b.end());

      len = a.size();
      //cout <<  "len " << len << endl;
      int s = 0;
      int e = len - 1;
      int ans = 0;
      while(s < len || e >= 0) {
        //cout << "s " << s << "  e " << e << endl;
        int now = a[s] + b[e];
        if (now == 0) {
          int tmp = a[s];
          int l1 = 0, l2 = 0;
          while(s < len && a[s] == tmp) {
            s++;
            l1++;
          }
          tmp = b[e];
          while(e >= 0 && b[e] == tmp) {
            e--;
            l2++;
          }
          ans += l1 * l2;
        } else if(now < 0) {
          s++;
        } else {
          e--;
        }
        //cout << "ans1 " << ans << endl;
        if (s == len) {
          while(e >= 0) {
            now = a[len - 1] + b[e];
            if (now == 0) {
              ans++;
              e--;
            }
            if (now < 0) {
              break;
            }
          }
          break;
        }

        if (e < 0) {
          while(s < len) {
            now = a[s] + b[0];
            if (now == 0) {
              ans++;
              s++;
            }
            if (now > 0) {
              break;
            }
          }
          break;
        }
      }
    return ans;
  }
};
```
