class Solution {
public:
    int fourSumCount(vector<int>& A, vector<int>& B, vector<int>& C, vector<int>& D) {
      int len = A.size();
      vector<int> a;
      vector<int> b;
      for (int i = 0; i < len; i++) {
        for (int j = 0; j < len; j++) {
          a.push_back(A[i] + B[j]);
          b.push_back(C[i] + D[j]);
        }
      }
      sort(a.begin(), a.end());
      sort(b.begin(), b.end());

      len = a.size();
      //cout <<  "len " << len << endl;
      int s = 0;
      int e = len - 1;
      int ans = 0;
      while(s < len || e >= 0) {
        //cout << "s " << s << "  e " << e << endl;
        int now = a[s] + b[e];
        if (now == 0) {
          int tmp = a[s];
          int l1 = 0, l2 = 0;
          while(s < len && a[s] == tmp) {
            s++;
            l1++;
          }
          tmp = b[e];
          while(e >= 0 && b[e] == tmp) {
            e--;
            l2++;
          }
          ans += l1 * l2;
        } else if(now < 0) {
          s++;
        } else {
          e--;
        }
        //cout << "ans1 " << ans << endl;
        if (s == len) {
          while(e >= 0) {
            now = a[len - 1] + b[e];
            if (now == 0) {
              ans++;
              e--;
            }
            if (now < 0) {
              break;
            }
          }
          break;
        }

        if (e < 0) {
          while(s < len) {
            now = a[s] + b[0];
            if (now == 0) {
              ans++;
              s++;
            }
            if (now > 0) {
              break;
            }
          }
          break;
        }
      }
    return ans;
  }
};
